#include "protocol.h"
#include "crc32.h"
#include <string.h>
static void reset(protocol_parser_t*p){p->state=PARSER_SOF0;p->index=0;p->needed=0;p->resets++;}
void protocol_parser_init(protocol_parser_t*p){if(p){memset(p,0,sizeof(*p));p->state=PARSER_SOF0;}}
status_t protocol_encode(const protocol_frame_t*f,uint8_t*out,size_t cap,size_t*used){if(!f||!out||!used||f->length>PROTOCOL_MAX_PAYLOAD)return STATUS_INVALID_ARGUMENT;size_t total=2u+6u+f->length+4u;if(cap<total)return STATUS_NO_SPACE;out[0]=PROTOCOL_SOF0;out[1]=PROTOCOL_SOF1;out[2]=f->version;out[3]=f->type;out[4]=f->flags;out[5]=f->sequence;out[6]=(uint8_t)f->length;out[7]=(uint8_t)(f->length>>8);memcpy(&out[8],f->payload,f->length);uint32_t c=crc32_compute(&out[2],6u+f->length);for(unsigned i=0;i<4;i++)out[8u+f->length+i]=(uint8_t)(c>>(8u*i));*used=total;return STATUS_OK;}
status_t protocol_parser_feed(protocol_parser_t*p,uint8_t b,protocol_frame_t*out,int*ready){if(!p||!out||!ready)return STATUS_INVALID_ARGUMENT;*ready=0;switch(p->state){case PARSER_SOF0:if(b==PROTOCOL_SOF0)p->state=PARSER_SOF1;break;case PARSER_SOF1:if(b==PROTOCOL_SOF1){p->state=PARSER_HEADER;p->index=0;}else p->state=(b==PROTOCOL_SOF0)?PARSER_SOF1:PARSER_SOF0;break;case PARSER_HEADER:p->scratch[p->index++]=b;if(p->index==6u){uint16_t len=(uint16_t)((uint16_t)p->scratch[4] | (uint16_t)((uint16_t)p->scratch[5] << 8u));if(len>PROTOCOL_MAX_PAYLOAD){reset(p);return STATUS_NO_SPACE;}p->needed=len;p->state=len?PARSER_PAYLOAD:PARSER_CRC;}break;case PARSER_PAYLOAD:p->scratch[p->index++]=b;if(p->index==6u+p->needed)p->state=PARSER_CRC;break;case PARSER_CRC:p->scratch[p->index++]=b;if(p->index==6u+p->needed+4u){size_t o=6u+p->needed;uint32_t got=(uint32_t)p->scratch[o]|((uint32_t)p->scratch[o+1]<<8)|((uint32_t)p->scratch[o+2]<<16)|((uint32_t)p->scratch[o+3]<<24);uint32_t calc=crc32_compute(p->scratch,6u+p->needed);if(got!=calc){p->crc_failures++;reset(p);return STATUS_CRC_ERROR;}out->version=p->scratch[0];out->type=p->scratch[1];out->flags=p->scratch[2];out->sequence=p->scratch[3];out->length=(uint16_t)p->needed;memcpy(out->payload,&p->scratch[6],p->needed);reset(p);*ready=1;}break;default:reset(p);return STATUS_CORRUPT;}return STATUS_OK;}
